// DB_FetchDueItems - Fetch items with due notifications via Supabase REST API
const supabaseUrl = 'https://chtkfksjqcvlxpgyzlsf.supabase.co';
const supabaseKey = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImNodGtma3NqcWN2bHhwZ3l6bHNmIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MjMwODU1NywiZXhwIjoyMDg3ODg0NTU3fQ.DM9wL7MlXRBuM_IYDk3pQ_q-WE7DYuwpqTTywg5A05U';

const now = new Date().toISOString();

try {
  const response = await this.helpers.httpRequest({
    method: 'GET',
    url: supabaseUrl + '/rest/v1/items?type=in.(reminder,task)&notification_datetime=lte.' + now + '&notification_sent_at=is.null&status=in.(open,doing)&select=*',
    headers: {
      'apikey': supabaseKey,
      'Authorization': 'Bearer ' + supabaseKey,
      'Content-Type': 'application/json'
    },
    json: true
  });

  if (Array.isArray(response) && response.length > 0) {
    return response.map(item => ({ json: item }));
  } else {
    return [{ json: { id: null, _no_items: true } }];
  }
} catch (e) {
  return [{ json: { id: null, _error: e.message } }];
}

// TRF_BuildReminderMessage - Monta mensagem de lembrete
const items = $input.all();
const results = [];

for (const inputItem of items) {
  const item = inputItem.json;
  const typeEmojis = { 'task': '📋', 'reminder': '⏰' };
  const emoji = typeEmojis[item.type] || '⏰';

  let message = emoji + ' *Lembrete:* ' + item.title;

  if (item.value) {
    message += '\n_' + item.value + '_';
  }

  if (item.event_datetime) {
    const eventDate = new Date(item.event_datetime);
    const options = { timeZone: 'America/Belem', day: '2-digit', month: '2-digit', year: 'numeric', hour: '2-digit', minute: '2-digit', hour12: false };
    message += '\n📅 ' + eventDate.toLocaleString('pt-BR', options);
  }

  results.push({
    json: {
      item_id: item.id,
      owner_phone: item.owner_phone,
      message: message,
      title: item.title
    }
  });
}

return results;

// API_ZAPI_SendReminder - Send reminder via Z-API with proper JSON handling
const items = $input.all();
const results = [];

for (const inputItem of items) {
  const item = inputItem.json;
  const phone = item.owner_phone;
  const message = item.message;

  try {
    const response = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.z-api.io/instances/3EF161BDC6931254B5992E8547AF841B/token/A3A3332D51363D4CBD61F10B/send-text',
      headers: {
        'Content-Type': 'application/json',
        'Client-Token': 'Fdb6aa1c0f1b74b2a8b3e4f5c6d7e8f9a0b1c2d3'
      },
      body: {
        phone: phone,
        message: message
      },
      json: true,
      timeout: 10000
    });

    results.push({
      json: {
        ...item,
        _zapi_success: true,
        _zapi_response: response
      }
    });
  } catch (e) {
    results.push({
      json: {
        ...item,
        _zapi_success: false,
        _zapi_error: e.message
      }
    });
  }
}

return results;

// DB_MarkNotified - Mark item as notified via Supabase REST API
const supabaseUrl = 'https://chtkfksjqcvlxpgyzlsf.supabase.co';
const supabaseKey = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImNodGtma3NqcWN2bHhwZ3l6bHNmIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MjMwODU1NywiZXhwIjoyMDg3ODg0NTU3fQ.DM9wL7MlXRBuM_IYDk3pQ_q-WE7DYuwpqTTywg5A05U';

const items = $input.all();
const results = [];

for (const inputItem of items) {
  const item = inputItem.json;
  const itemId = item.item_id;

  if (!itemId) {
    results.push({ json: { ...item, _mark_error: 'No item_id' } });
    continue;
  }

  try {
    await this.helpers.httpRequest({
      method: 'PATCH',
      url: supabaseUrl + '/rest/v1/items?id=eq.' + itemId,
      headers: {
        'apikey': supabaseKey,
        'Authorization': 'Bearer ' + supabaseKey,
        'Content-Type': 'application/json',
        'Prefer': 'return=representation'
      },
      body: {
        notification_sent_at: new Date().toISOString(),
        status: 'notified'
      },
      json: true
    });
    results.push({ json: { ...item, _marked: true } });
  } catch (e) {
    results.push({ json: { ...item, _mark_error: e.message } });
  }
}

return results;

// LOG_ReminderSent - Log de lembrete enviado
