return {
  json: {
    status: 'sent',
    item_id: reminderData.item_id,
    owner_phone: reminderData.owner_phone,
    title: reminderData.title,
    sent_at: new Date().toISOString()
  }
};

// LOG_ReminderFailed - Log de falha no envio
const reminderData = $('TRF_BuildReminderMessage').first().json;
const error = $input.first().json;

return {
  json: {
    status: 'failed',
    item_id: reminderData.item_id,
    owner_phone: reminderData.owner_phone,
    title: reminderData.title,
    error: error.message || JSON.stringify(error),
    failed_at: new Date().toISOString()
  }
};

// LOG_NoReminders - Nenhum lembrete pendente
return {
  json: {
    status: 'no_reminders',
    checked_at: new Date().toISOString()
  }
};

